 */
package org.opendataloader.pdf.processors;

import org.opendataloader.pdf.containers.StaticLayoutContainers;
import org.junit.jupiter.api.Assertions;
import org.junit.jupiter.api.Test;
import org.verapdf.tools.StaticResources;
import org.verapdf.wcag.algorithms.entities.IObject;
import org.verapdf.wcag.algorithms.entities.SemanticHeaderOrFooter;
import org.verapdf.wcag.algorithms.entities.content.TextChunk;
import org.verapdf.wcag.algorithms.entities.content.TextLine;
import org.verapdf.wcag.algorithms.entities.enums.SemanticType;
import org.verapdf.wcag.algorithms.entities.geometry.BoundingBox;
import org.verapdf.wcag.algorithms.semanticalgorithms.containers.StaticContainers;

import java.util.ArrayList;
import java.util.List;

public class HeaderFooterProcessorTest {

    @Test
    public void testProcessHeadersAndFooters() {
        StaticContainers.setIsDataLoader(true);
        StaticContainers.setIsIgnoreCharactersWithoutUnicode(false);
        StaticResources.setDocument(null);
        StaticLayoutContainers.clearContainers();
        List<List<IObject>> contents = new ArrayList<>();
        List<IObject> page1Contents = new ArrayList<>();
        page1Contents.add(new TextLine(new TextChunk(new BoundingBox(0, 10.0, 30.0, 20.0, 40.0),
            "Header", 10, 30.0)));
        page1Contents.add(new TextLine(new TextChunk(new BoundingBox(0, 10.0, 20.0, 20.0, 30.0),
            "Text", 10, 20.0)));
        page1Contents.add(new TextLine(new TextChunk(new BoundingBox(0, 10.0, 10.0, 20.0, 20.0),
            "Footer1", 10, 10.0)));
        List<IObject> page2Contents = new ArrayList<>();
        page2Contents.add(new TextLine(new TextChunk(new BoundingBox(1, 10.0, 30.0, 20.0, 40.0),
            "Header", 10, 30.0)));
        page2Contents.add(new TextLine(new TextChunk(new BoundingBox(1, 10.0, 20.0, 20.0, 30.0),
            "Different Text", 10, 20.0)));
        page2Contents.add(new TextLine(new TextChunk(new BoundingBox(1, 10.0, 10.0, 20.0, 20.0),
            "Footer2", 10, 10.0)));
        contents.add(page1Contents);
        contents.add(page2Contents);
        HeaderFooterProcessor.processHeadersAndFooters(contents, false);

        Assertions.assertEquals(3, contents.get(0).size());
        Assertions.assertEquals(3, contents.get(1).size());

        Assertions.assertTrue(contents.get(0).get(0) instanceof SemanticHeaderOrFooter);
        Assertions.assertEquals(SemanticType.HEADER, ((SemanticHeaderOrFooter) contents.get(0).get(0)).getSemanticType());
        Assertions.assertTrue(contents.get(1).get(0) instanceof SemanticHeaderOrFooter);
        Assertions.assertEquals(SemanticType.HEADER, ((SemanticHeaderOrFooter) contents.get(1).get(0)).getSemanticType());
        Assertions.assertTrue(contents.get(0).get(2) instanceof SemanticHeaderOrFooter);
        Assertions.assertEquals(SemanticType.FOOTER, ((SemanticHeaderOrFooter) contents.get(0).get(2)).getSemanticType());
        Assertions.assertTrue(contents.get(1).get(2) instanceof SemanticHeaderOrFooter);
        Assertions.assertEquals(SemanticType.FOOTER, ((SemanticHeaderOrFooter) contents.get(1).get(2)).getSemanticType());
    }

    /**
     * Reproduces bug #354: Footer detection absorbs body text on pages with nearby notes.
     *
     * Scenario: Pages have actual footer text at the bottom of the page AND
     * a body note that repeats across pages and is spatially close to the footer.
     * The footer detection should NOT include the body note in the footer element.
     */
    @Test
    public void testFooterDetectionDoesNotAbsorbNearbyBodyText() {
        StaticContainers.setIsDataLoader(true);
        StaticContainers.setIsIgnoreCharactersWithoutUnicode(false);
        StaticResources.setDocument(null);
        StaticLayoutContainers.clearContainers();

        // Simulate a page with height ~800 (like A4)
        // Footer text at topY=44, bottomY=35  (very close to page bottom)
        // Body note at topY=135, bottomY=120 (near the footer but separate body text)
        // Body text at topY=650, bottomY=630 (main body content)

        List<List<IObject>> contents = new ArrayList<>();

        // Page 19: Footer + body note + body text
        List<IObject> page19Contents = new ArrayList<>();
        // Body text (top of page)
        page19Contents.add(new TextLine(new TextChunk(
            new BoundingBox(19, 50.0, 630.0, 150.0, 650.0),
            "Body text on page 19", 10, 10.0)));
        // Body note (repeating, near footer)
        page19Contents.add(new TextLine(new TextChunk(
            new BoundingBox(19, 50.0, 120.0, 200.0, 135.0),
            "\u203B Note text repeating across pages", 10, 10.0)));
        // Actual footer
        page19Contents.add(new TextLine(new TextChunk(
            new BoundingBox(19, 50.0, 35.0, 200.0, 44.0),
            "19 CERAGEM BALANCE USER MANUAL", 10, 10.0)));

        // Page 20: Footer + body note + body text (note repeats, different body)
        List<IObject> page20Contents = new ArrayList<>();
        page20Contents.add(new TextLine(new TextChunk(
            new BoundingBox(20, 50.0, 630.0, 150.0, 650.0),
            "Body text on page 20 - different", 10, 10.0)));
        page20Contents.add(new TextLine(new TextChunk(
            new BoundingBox(20, 50.0, 120.0, 200.0, 135.0),
            "\u203B Note text repeating across pages", 10, 10.0)));
        page20Contents.add(new TextLine(new TextChunk(
            new BoundingBox(20, 50.0, 35.0, 200.0, 44.0),
            "20 CERAGEM BALANCE USER MANUAL", 10, 10.0)));

        // Page 21: Footer + body text (NO note)
        List<IObject> page21Contents = new ArrayList<>();
        page21Contents.add(new TextLine(new TextChunk(
            new BoundingBox(21, 50.0, 630.0, 150.0, 650.0),
            "Body text on page 21 - different", 10, 10.0)));
        page21Contents.add(new TextLine(new TextChunk(
            new BoundingBox(21, 50.0, 35.0, 200.0, 44.0),
            "21 CERAGEM BALANCE USER MANUAL", 10, 10.0)));

        contents.add(page19Contents);
        contents.add(page20Contents);
        contents.add(page21Contents);

        HeaderFooterProcessor.processHeadersAndFooters(contents, false);

        // Check page 19: footer should only contain the actual footer, not the note
        for (IObject content : contents.get(0)) {
            if (content instanceof SemanticHeaderOrFooter) {
                SemanticHeaderOrFooter hf = (SemanticHeaderOrFooter) content;
                if (hf.getSemanticType() == SemanticType.FOOTER) {
                    // Footer should contain only the footer text, not the note
                    BoundingBox bbox = hf.getBoundingBox();
                    // Footer topY should be around 44 (just the footer), not 135 (including the note)
                    // Check that footer height is reasonable (less than 30pt)
                    double footerHeight = bbox.getTopY() - bbox.getBottomY();
                    Assertions.assertTrue(footerHeight < 30.0,
                        "Footer height should be small (< 30pt) but was: " + footerHeight +
                        ". Footer topY=" + bbox.getTopY() + ", bottomY=" + bbox.getBottomY());
                    // Footer top should be near the actual footer text, not near the note
                    Assertions.assertTrue(bbox.getTopY() < 60.0,
                        "Footer topY should be near 44 but was: " + bbox.getTopY());
                }
            }
        }

        // Check page 20: same checks
        for (IObject content : contents.get(1)) {
            if (content instanceof SemanticHeaderOrFooter) {
                SemanticHeaderOrFooter hf = (SemanticHeaderOrFooter) content;
                if (hf.getSemanticType() == SemanticType.FOOTER) {
                    double footerHeight = hf.getBoundingBox().getTopY() - hf.getBoundingBox().getBottomY();
                    Assertions.assertTrue(footerHeight < 30.0,
                        "Footer height should be small (< 30pt) but was: " + footerHeight);
                    Assertions.assertTrue(hf.getBoundingBox().getTopY() < 60.0,
                        "Footer topY should be near 44 but was: " + hf.getBoundingBox().getTopY());
                }
            }
        }

        // Check page 21: footer should be detected correctly (no note to absorb)
        for (IObject content : contents.get(2)) {
            if (content instanceof SemanticHeaderOrFooter) {
                SemanticHeaderOrFooter hf = (SemanticHeaderOrFooter) content;
                if (hf.getSemanticType() == SemanticType.FOOTER) {
                    double footerHeight = hf.getBoundingBox().getTopY() - hf.getBoundingBox().getBottomY();
                    Assertions.assertTrue(footerHeight < 30.0,
                        "Footer height should be small (< 30pt) but was: " + footerHeight);
                }
            }
        }
    }

    /**
     * Reproduces bug #354: Footer text leaks into Markdown instead of being filtered.
     *
     * Verifies that pages 6 and 20 (which have footer text at the bottom) are properly
     * detected and will be filtered from output.
     */
    @Test
    public void testFooterTextIsProperlyDetectedAndNotLeaked() {
        StaticContainers.setIsDataLoader(true);
        StaticContainers.setIsIgnoreCharactersWithoutUnicode(false);
        StaticResources.setDocument(null);
        StaticLayoutContainers.clearContainers();

        List<List<IObject>> contents = new ArrayList<>();

        // Page 6: Footer text "06 CERAGEM BALANCE USER MANUAL"
        List<IObject> page6Contents = new ArrayList<>();
        page6Contents.add(new TextLine(new TextChunk(
            new BoundingBox(6, 50.0, 630.0, 200.0, 650.0),
            "Body content page 6", 10, 10.0)));
        page6Contents.add(new TextLine(new TextChunk(
            new BoundingBox(6, 50.0, 35.0, 200.0, 44.0),
            "06 CERAGEM BALANCE USER MANUAL", 10, 10.0)));

        // Page 7: Different page with similar footer pattern
        List<IObject> page7Contents = new ArrayList<>();
        page7Contents.add(new TextLine(new TextChunk(
            new BoundingBox(7, 50.0, 630.0, 200.0, 650.0),
            "Body content page 7", 10, 10.0)));
        page7Contents.add(new TextLine(new TextChunk(
            new BoundingBox(7, 50.0, 35.0, 200.0, 44.0),
            "07 CERAGEM BALANCE USER MANUAL", 10, 10.0)));

        contents.add(page6Contents);
        contents.add(page7Contents);

        HeaderFooterProcessor.processHeadersAndFooters(contents, false);

        // Check that footer is detected on both pages
        // The footer text should be inside a SemanticHeaderOrFooter element, not as a raw TextLine
        boolean foundFooter6 = false;
        for (IObject content : contents.get(0)) {
            if (content instanceof SemanticHeaderOrFooter &&
                ((SemanticHeaderOrFooter) content).getSemanticType() == SemanticType.FOOTER) {
                foundFooter6 = true;
                break;
            }
        }
        Assertions.assertTrue(foundFooter6, "Footer should be detected on page 6");

        boolean foundFooter7 = false;
        for (IObject content : contents.get(1)) {
            if (content instanceof SemanticHeaderOrFooter &&
                ((SemanticHeaderOrFooter) content).getSemanticType() == SemanticType.FOOTER) {
                foundFooter7 = true;
                break;
            }
        }
        Assertions.assertTrue(foundFooter7, "Footer should be detected on page 7");
    }
}

