        contents.add(page21Contents);

        HeaderFooterProcessor.processHeadersAndFooters(contents, false);

        // Check page 19: footer should only contain the actual footer, not the note
        for (IObject content : contents.get(0)) {
            if (content instanceof SemanticHeaderOrFooter) {
                SemanticHeaderOrFooter hf = (SemanticHeaderOrFooter) content;
                if (hf.getSemanticType() == SemanticType.FOOTER) {
                    // Footer should contain only the footer text, not the note
                    BoundingBox bbox = hf.getBoundingBox();
                    // Footer topY should be around 44 (just the footer), not 135 (including the note)
                    // Check that footer height is reasonable (less than 30pt)
                    double footerHeight = bbox.getTopY() - bbox.getBottomY();
                    Assertions.assertTrue(footerHeight < 30.0,
                        "Footer height should be small (< 30pt) but was: " + footerHeight +
                        ". Footer topY=" + bbox.getTopY() + ", bottomY=" + bbox.getBottomY());
                    // Footer top should be near the actual footer text, not near the note
                    Assertions.assertTrue(bbox.getTopY() < 60.0,
                        "Footer topY should be near 44 but was: " + bbox.getTopY());
                }
            }
        }

        // Check page 20: same checks
        for (IObject content : contents.get(1)) {
            if (content instanceof SemanticHeaderOrFooter) {
                SemanticHeaderOrFooter hf = (SemanticHeaderOrFooter) content;
                if (hf.getSemanticType() == SemanticType.FOOTER) {
                    double footerHeight = hf.getBoundingBox().getTopY() - hf.getBoundingBox().getBottomY();
                    Assertions.assertTrue(footerHeight < 30.0,
                        "Footer height should be small (< 30pt) but was: " + footerHeight);
                    Assertions.assertTrue(hf.getBoundingBox().getTopY() < 60.0,
                        "Footer topY should be near 44 but was: " + hf.getBoundingBox().getTopY());
                }
            }
        }

        // Check page 21: footer should be detected correctly (no note to absorb)
        for (IObject content : contents.get(2)) {
            if (content instanceof SemanticHeaderOrFooter) {
                SemanticHeaderOrFooter hf = (SemanticHeaderOrFooter) content;
                if (hf.getSemanticType() == SemanticType.FOOTER) {
                    double footerHeight = hf.getBoundingBox().getTopY() - hf.getBoundingBox().getBottomY();
                    Assertions.assertTrue(footerHeight < 30.0,
                        "Footer height should be small (< 30pt) but was: " + footerHeight);
                }
            }
        }
    }

    /**
     * Reproduces bug #354: Footer text leaks into Markdown instead of being filtered.
     *
     * Verifies that pages 6 and 20 (which have footer text at the bottom) are properly
     * detected and will be filtered from output.
     */
    @Test
    public void testFooterTextIsProperlyDetectedAndNotLeaked() {
        StaticContainers.setIsDataLoader(true);
        StaticContainers.setIsIgnoreCharactersWithoutUnicode(false);
        StaticResources.setDocument(null);
        StaticLayoutContainers.clearContainers();

        List<List<IObject>> contents = new ArrayList<>();

        // Page 6: Footer text "06 CERAGEM BALANCE USER MANUAL"
        List<IObject> page6Contents = new ArrayList<>();
        page6Contents.add(new TextLine(new TextChunk(
            new BoundingBox(6, 50.0, 630.0, 200.0, 650.0),
            "Body content page 6", 10, 10.0)));
        page6Contents.add(new TextLine(new TextChunk(
            new BoundingBox(6, 50.0, 35.0, 200.0, 44.0),
            "06 CERAGEM BALANCE USER MANUAL", 10, 10.0)));

        // Page 7: Different page with similar footer pattern
        List<IObject> page7Contents = new ArrayList<>();
        page7Contents.add(new TextLine(new TextChunk(
            new BoundingBox(7, 50.0, 630.0, 200.0, 650.0),
            "Body content page 7", 10, 10.0)));
        page7Contents.add(new TextLine(new TextChunk(
            new BoundingBox(7, 50.0, 35.0, 200.0, 44.0),
            "07 CERAGEM BALANCE USER MANUAL", 10, 10.0)));

        contents.add(page6Contents);
        contents.add(page7Contents);

        HeaderFooterProcessor.processHeadersAndFooters(contents, false);

        // Check that footer is detected on both pages
        // The footer text should be inside a SemanticHeaderOrFooter element, not as a raw TextLine
        boolean foundFooter6 = false;
        for (IObject content : contents.get(0)) {
            if (content instanceof SemanticHeaderOrFooter &&
                ((SemanticHeaderOrFooter) content).getSemanticType() == SemanticType.FOOTER) {
                foundFooter6 = true;
                break;
            }
        }
        Assertions.assertTrue(foundFooter6, "Footer should be detected on page 6");

        boolean foundFooter7 = false;
        for (IObject content : contents.get(1)) {
            if (content instanceof SemanticHeaderOrFooter &&
                ((SemanticHeaderOrFooter) content).getSemanticType() == SemanticType.FOOTER) {
                foundFooter7 = true;
                break;
            }
        }
        Assertions.assertTrue(foundFooter7, "Footer should be detected on page 7");
    }
}

