private static List<IObject> filterHeaderOrFooterContents(List<IObject> contents, int pageNumber, boolean isHeaderDetection) {
        BoundingBox boundingBox = DocumentProcessor.getPageBoundingBox(pageNumber);
        if (boundingBox == null) {
            return contents;
        }
        List<IObject> result = new ArrayList<>();
        double pageHeight = boundingBox.getHeight();

        // Iterate from the page edge outward (bottom-to-top for footers, top-to-bottom for headers)
        // Stop including elements when a significant gap is detected between consecutive candidates.
        // This prevents body text near the header/footer region from being absorbed.
        double maxEdgeDistance = pageHeight / 4;  // first element must be within this distance from the page edge
        double maxGap = pageHeight / 8;           // subsequent elements must not have a gap larger than this

        Double previousEdgeCoordinate = null;

        // Iterate from the edge of the page toward the center
        for (int i = contents.size() - 1; i >= 0; i--) {
            IObject content = contents.get(i);
            double currentEdgeCoordinate;  // the coordinate closest to the page edge for this element

            if (isHeaderDetection) {
                // Header: edge is the top of the page (largest Y value)
                currentEdgeCoordinate = content.getBottomY();  // distance from bottom of element to page bottom
                double distanceFromTop = pageHeight - content.getBottomY();

                if (result.isEmpty() && distanceFromTop > maxEdgeDistance) {
                    continue;  // first element too far from top edge
                }
                if (!result.isEmpty()) {
                    double gap = previousEdgeCoordinate - content.getBottomY();
                    if (gap > maxGap) {
                        break;  // gap too large, stop including
                    }
                }
                previousEdgeCoordinate = content.getTopY();
            } else {
                // Footer: edge is the bottom of the page (smallest Y value)
                currentEdgeCoordinate = content.getTopY();  // distance from top of element to page bottom

                if (result.isEmpty() && currentEdgeCoordinate > maxEdgeDistance) {
                    continue;  // first element too far from bottom edge
                }
                if (!result.isEmpty()) {
                    double gap = content.getTopY() - previousEdgeCoordinate;
                    if (gap > maxGap) {
                        break;  // gap too large, stop including
                    }
                }
                previousEdgeCoordinate = content.getBottomY();
            }
            result.add(0, content);  // prepend to maintain original order
        }
        return result;
    }

