private static List<IObject> filterHeaderOrFooterContents(List<IObject> contents, int pageNumber, List<IObject> allPageContents, boolean isHeaderDetection) {
        BoundingBox boundingBox = DocumentProcessor.getPageBoundingBox(pageNumber);
        double pageHeight;
        if (boundingBox != null) {
            pageHeight = boundingBox.getHeight();
        } else {
            // Fallback: use the maximum topY of all page contents to estimate page height
            double maxTopY = 0;
            for (IObject content : allPageContents) {
                if (content.getTopY() > maxTopY) {
                    maxTopY = content.getTopY();
                }
            }
            if (maxTopY <= 0) {
                return contents;
            }
            pageHeight = maxTopY;
        }

        List<IObject> result = new ArrayList<>();

        // Iterate from the page edge outward (bottom-to-top for footers, top-to-bottom for headers).
        // The first candidate (closest to the page edge) is accepted if it is within the outer
        // half of the page. Subsequent elements are only accepted if they are within a small gap
        // of the previous accepted element, to prevent body text from being absorbed.
        double firstElementMaxDistance = pageHeight / 2;    // first element must be in the outer half
        double maxGap = Math.max(pageHeight / 10, 18.0);   // subsequent elements must not have a gap larger than this

        Double previousEdgeCoordinate = null;

        // Iterate from the edge of the page toward the center
        for (int i = contents.size() - 1; i >= 0; i--) {
            IObject content = contents.get(i);

            if (isHeaderDetection) {
                // Header: edge is the top of the page (largest Y value)
                double distanceFromTop = pageHeight - content.getBottomY();

                if (result.isEmpty() && distanceFromTop > firstElementMaxDistance) {
                    continue;  // first element too far from top edge
                }
                if (!result.isEmpty()) {
                    double gap = previousEdgeCoordinate - content.getBottomY();
                    if (gap > maxGap) {
                        break;  // gap too large, stop including subsequent elements
                    }
                }
                previousEdgeCoordinate = content.getTopY();
            } else {
                // Footer: edge is the bottom of the page (smallest Y value)
                double distanceFromBottom = content.getTopY();

                if (result.isEmpty() && distanceFromBottom > firstElementMaxDistance) {
                    continue;  // first element too far from bottom edge
                }
                if (!result.isEmpty()) {
                    double gap = content.getTopY() - previousEdgeCoordinate;
                    if (gap > maxGap) {
                        break;  // gap too large, stop including subsequent elements
                    }
                }
                previousEdgeCoordinate = content.getBottomY();
            }
            result.add(0, content);  // prepend to maintain original order
        }
        return result;
    }

